mapper.select:
select asset_id, name, request_host, risk_level, status
from asset

    deleted = 0
    and name like concat('%',#{param.name},'%')
    and request_host like concat('%',#{param.requestHost},'%')
    and risk_level = #{param.riskLevel}
    and status = #{param.status}
    and category_id = #{param.categoryId}

order by name desc
